SELECT DISTINCT users.username, users.email
FROM violations
INNER JOIN users ON violations.inspector_id = users.user_id;

SELECT * 
FROM mines
WHERE opening_date < date('now', '-5 years');

SELECT certificate_number
FROM compliance_training_records
WHERE certificate_number IS NOT NULL;

SELECT m.mine_name, v.standard_violated, v.violation_description, v.violation_date, v.penalty_paid
FROM mines m
INNER JOIN violations v ON m.mine_id = v.mine_id;

SELECT incident_id, mine_id, incident_type, report_date, details, reported_by, severity, action_taken
FROM incident_reports
WHERE severity = 'major' OR severity = 'critical';

SELECT username 
FROM users 
WHERE user_id NOT IN (SELECT DISTINCT user_id FROM compliance_training_records);
